  1	import * as React from 'react';
  2	import { ProtectedApplicationViewKind } from '@odf/mco/types/pav';
  3	import { DRPlacementControlModel } from '@odf/shared';
  4	import { ActionDropdownItems } from '@odf/shared/dropdown/action-dropdown';
  5	import { getName, getNamespace } from '@odf/shared/selectors';
  6	import {
  7	  GrayUnknownIcon,
  8	  GreenCheckCircleIcon,
  9	  RedExclamationCircleIcon,
 10	  YellowExclamationTriangleIcon,
 11	} from '@odf/shared/status/icons';
 12	import { sortRows, referenceForModel } from '@odf/shared/utils';
 13	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 14	import * as _ from 'lodash-es';
 15	import { TFunction } from 'react-i18next';
 16	import { NavigateFunction } from 'react-router-dom-v5-compat';
 17	import {
 18	  AlertProps,
 19	  AlertVariant,
 20	  AlertActionCloseButton,
 21	} from '@patternfly/react-core';
 22	import { IAction } from '@patternfly/react-table';
 23	import {
 24	  VolumeReplicationHealth,
 25	  DRPCStatus,
 26	  DR_BASE_ROUTE,
 27	  DRActionType,
 28	  ReplicationType,
 29	  ApplicationType,
 30	} from '../../constants';
 31	import { DRPlacementControlKind, Progression } from '../../types';
 32	import { DRPlacementControlParser } from '../modals/app-failover-relocate/parser/discovered-application-parser';
 33	import { AppManagePoliciesModalWrapper } from '../modals/protected-applications/app-manage-policies-modal-wrapper';
 34	import { ApplicationActionModal } from '../modals/protected-applications/applications-action-modal';
 35	import RemoveDisasterRecoveryModal from '../modals/remove-disaster-recovery/remove-disaster-recovery';
 36	
 37	export const drpcDetailsPageRoute = (drpc: DRPlacementControlKind) =>
 38	  `/k8s/ns/${getNamespace(drpc)}/${referenceForModel(
 39	    DRPlacementControlModel
 40	  )}/${getName(drpc)}`;
 41	
 42	export const getAlertMessages = (
 43	  t: TFunction<string>,
 44	  application: string,
 45	  navigate: NavigateFunction,
 46	  relocatedApp?: string,
 47	  relocatedCluster?: string,
 48	  failedOverApp?: string,
 49	  failedOverCluster?: string
 50	): AlertProps[] => [
 51	  ...(!!application
 52	    ? [
 53	        {
 54	          variant: AlertVariant.success,
 55	          title: t(
 56	            '{{appName}} is now successfully enrolled for disaster recovery protection.',
 57	            { appName: application }
 58	          ),
 59	          actionClose: (
 60	            <AlertActionCloseButton
 61	              onClose={() =>
 62	                navigate(`${DR_BASE_ROUTE}/protected-applications`)
 63	              }
 64	            />
 65	          ),
 66	          isInline: true,
 67	          key: 'enrolled_success',
 68	        },
 69	      ]
 70	    : []),
 71	  ...(!!relocatedApp && !!relocatedCluster
 72	    ? [
 73	        {
 74	          variant: AlertVariant.success,
 75	          title: t('{{appName}} relocated', { appName: relocatedApp }),
 76	          children: t(
 77	            'Application "{{appName}}" is now deployed on cluster {{cluster}}',
 78	            { appName: relocatedApp, cluster: relocatedCluster }
 79	          ),
 80	          actionClose: (
 81	            <AlertActionCloseButton
 82	              onClose={() =>
 83	                navigate(`${DR_BASE_ROUTE}/protected-applications`)
 84	              }
 85	            />
 86	          ),
 87	          isInline: true,
 88	          key: 'relocated_success',
 89	        },
 90	      ]
 91	    : []),
 92	  ...(!!failedOverApp && !!failedOverCluster
 93	    ? [
 94	        {
 95	          variant: AlertVariant.success,
 96	          title: t('{{appName}} failed over', { appName: failedOverApp }),
 97	          children: t(
 98	            'Application "{{appName}}" is now deployed on cluster {{cluster}}',
 99	            { appName: failedOverApp, cluster: failedOverCluster }
100	          ),
101	          actionClose: (
102	            <AlertActionCloseButton
103	              onClose={() =>
104	                navigate(`${DR_BASE_ROUTE}/protected-applications`)
105	              }
106	            />
107	          ),
108	          isInline: true,
109	          key: 'failedover_success',
110	        },
111	      ]
112	    : []),
113	  {
114	    variant: AlertVariant.info,
115	    title: t(
116	      'For disaster recovery or replication details about ACM managed applications navigate to Applications overview page.'
117	    ),
118	    isInline: true,
119	    key: 'navigation_info',
120	  },
121	];
122	
123	export const isFailingOrRelocating = (
124	  application: DRPlacementControlKind
125	): boolean =>
126	  [DRPCStatus.FailingOver, DRPCStatus.Relocating].includes(
127	    application?.status?.phase as DRPCStatus
128	  );
129	
130	export const isCleanupPending = (drpc: DRPlacementControlKind): boolean =>
131	  [DRPCStatus.FailedOver, DRPCStatus.Relocating].includes(
132	    drpc?.status?.phase as DRPCStatus
133	  ) && drpc?.status?.progression === Progression.WaitOnUserToCleanUp;
134	
135	export type ReplicationHealthMap = {
136	  title: string;
137	  icon: JSX.Element;
138	  priority: number;
139	};
140	
141	export const replicationHealthMap = (
142	  health: VolumeReplicationHealth,
143	  t: TFunction<string>
144	): ReplicationHealthMap => {
145	  switch (health) {
146	    case VolumeReplicationHealth.CRITICAL:
147	      return {
148	        title: t('Critical'),
149	        icon: <RedExclamationCircleIcon />,
150	        priority: 3,
151	      };
152	    case VolumeReplicationHealth.WARNING:
153	      return {
154	        title: t('Warning'),
155	        icon: <YellowExclamationTriangleIcon />,
156	        priority: 2,
157	      };
158	    case VolumeReplicationHealth.HEALTHY:
159	      return {
160	        title: t('Healthy'),
161	        icon: <GreenCheckCircleIcon />,
162	        priority: 0,
163	      };
164	    default:
165	      return {
166	        title: t('Unknown'),
167	        icon: <GrayUnknownIcon />,
168	        priority: 1,
169	      };
170	  }
171	};
172	
173	export type SyncStatusInfo = {
174	  volumeReplicationStatus: VolumeReplicationHealth;
175	  volumeReplicationType: ReplicationType;
176	  volumeLastGroupSyncTime: string;
177	  kubeObjectReplicationStatus: VolumeReplicationHealth;
178	  kubeObjectLastProtectionTime: string;
179	  replicationType: ReplicationType;
180	  schedulingInterval?: string;
181	};
182	
183	export const getAppWorstSyncStatus = (
184	  syncStatusInfo: SyncStatusInfo,
185	  t: TFunction<string>
186	): ReplicationHealthMap => {
187	  const volumeStatus = syncStatusInfo.volumeReplicationStatus;
188	  const kubeObjectStatus = syncStatusInfo.kubeObjectReplicationStatus;
189	  const volumeStatusObj = replicationHealthMap(volumeStatus, t);
190	  const kubeObjectStatusObj = replicationHealthMap(kubeObjectStatus, t);
191	  return volumeStatusObj.priority > kubeObjectStatusObj.priority
192	    ? volumeStatusObj
193	    : kubeObjectStatusObj;
194	};
195	
196	export const getColumnNames = (t: TFunction<string>) => [
197	  '', // expandable icon
198	  t('Name'),
199	  t('DR Status'),
200	  t('Policy'),
201	  t('Cluster'),
202	  '', // action kebab
203	];
204	
205	export const getHeaderColumns = (t: TFunction<string>) => {
206	  const columnNames = getColumnNames(t);
207	  return [
208	    {
209	      columnName: columnNames[0],
210	    },
211	    {
212	      columnName: columnNames[1],
213	      sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name'),
214	    },
215	    {
216	      columnName: columnNames[2],
217	    },
218	    {
219	      columnName: columnNames[3],
220	    },
221	    {
222	      columnName: columnNames[4],
223	      sortFunction: (a, b, c) => sortRows(a, b, c, 'spec.drPolicyRef.name'),
224	    },
225	    {
226	      columnName: columnNames[5],
227	    },
228	  ];
229	};
230	
231	export const getRowActions = (
232	  t: TFunction<string>,
233	  launcher: LaunchModal,
234	  navigate: NavigateFunction,
235	  drpc: DRPlacementControlKind | undefined,
236	  pav: ProtectedApplicationViewKind
237	): IAction[] => {
238	  if (!drpc) {
239	    return [];
240	  }
241	
242	  const appInfo = pav.status?.applicationInfo;
243	  const isDiscoveredApp = appInfo?.type === ApplicationType.Discovered;
244	
245	  const launchDRAction = (action: DRActionType) =>
246	    isDiscoveredApp
247	      ? launcher(DRPlacementControlParser, {
248	          isOpen: true,
249	          extraProps: { application: drpc, action },
250	        })
251	      : launcher(ApplicationActionModal, {
252	          isOpen: true,
253	          extraProps: { pav, action },
254	        });
255	
256	  return [
257	    {
258	      title: (
259	        <>
260	          {t('Edit configuration')}
261	          <p className="text-muted pf-v6-u-font-size-xs">
262	            {t('Update existing configuration in YAML view')}
263	          </p>
264	        </>
265	      ),
266	      onClick: () => navigate(`${drpcDetailsPageRoute(drpc)}/yaml`),
267	    },
268	    {
269	      title: (
270	        <>
271	          {t('Failover')}
272	          <p className="text-muted pf-v6-u-font-size-xs">
273	            {t('Move workloads to target cluster')}
274	          </p>
275	        </>
276	      ),
277	      onClick: () => launchDRAction(DRActionType.FAILOVER),
278	    },
279	    {
280	      title: (
281	        <>
282	          {t('Relocate')}
283	          <p className="text-muted pf-v6-u-font-size-xs">
284	            {t('Failback workloads to primary cluster')}
285	          </p>
286	        </>
287	      ),
288	      onClick: () => launchDRAction(DRActionType.RELOCATE),
289	    },
290	    isDiscoveredApp
291	      ? {
292	          title: t('Remove disaster recovery'),
293	          ...(_.has(drpc.metadata, 'deletionTimestamp') && {
294	            isAriaDisabled: true,
295	            tooltipProps: {
296	              content: t('Resource is being deleted.'),
297	              trigger: 'mouseenter',
298	            },
299	          }),
300	          onClick: () =>
301	            launcher(RemoveDisasterRecoveryModal, {
302	              isOpen: true,
303	              extraProps: { application: drpc },
304	            }),
305	        }
306	      : {
307	          title: (
308	            <>
309	              {t('Manage disaster recovery')}
310	              <p className="text-muted pf-v6-u-font-size-xs">
311	                {t('Update DR policies and configuration')}
312	              </p>
313	            </>
314	          ),
315	          onClick: () =>
316	            launcher(AppManagePoliciesModalWrapper, {
317	              isOpen: true,
318	              extraProps: { pav },
319	            }),
320	        },
321	  ];
322	};
323	export const enum EnrollApplicationTypes {
324	  CHOOSE_TYPE = 'CHOOSE_TYPE',
325	  DISCOVERED = 'DISCOVERED',
326	  MANAGED = 'MANAGED',
327	}
328	
329	export const getEnrollDropdownItems = (
330	  t: TFunction<string>
331	): ActionDropdownItems[] => [
332	  {
333	    id: EnrollApplicationTypes.CHOOSE_TYPE,
334	    isDisabled: true,
335	    text: t('Choose a type:'),
336	  },
337	  {
338	    id: EnrollApplicationTypes.DISCOVERED,
339	    isDisabled: false,
340	    text: t('ACM discovered applications'),
341	  },
342	  {
343	    id: EnrollApplicationTypes.MANAGED,
344	    isDisabled: false,
345	    text: t('ACM managed applications'),
346	  },
347	];

